{
  "family": "Pfitzner-Moffatt Oxidation",
  "candidate": {
    "substrate_smiles": [
      "CCCCCO"
    ],
    "product_smiles": [
      "CCCCC=O"
    ],
    "optional_reagent_smiles": [
      "CS(C)=O",
      "C1CCCCC(N=C=NC2CCCCC2)C1",
      "Cl.c1cc[nH+]cc1"
    ],
    "rationale": "This reaction shows the oxidation of a simple primary alcohol (1-pentanol) to the corresponding aldehyde (pentanal). This is a classic textbook example of the Pfitzner-Moffatt oxidation. The reagents shown are dimethyl sulfoxide (DMSO), dicyclohexylcarbodiimide (DCC), and pyridinium hydrochloride as the mild acid catalyst, which are the defining components of this named reaction. The acyclic, unfunctionalized substrate is chosen for its simplicity and to avoid ambiguity with other named reactions.",
    "collision_avoidance_note": "The substrate is a simple primary alcohol, avoiding complex structures, rings, or other functional groups that could trigger unrelated reaction families. The specific combination of DMSO, a carbodiimide (DCC), and a mild acid catalyst is highly characteristic of the Pfitzner-Moffatt oxidation, distinguishing it from other activated-DMSO oxidations like the Swern (oxalyl chloride) or Parikh-Doering (SO3-pyridine) oxidations."
  }
}
